using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // GET all shipments (dispatchers only)
        group.MapGet("/", async (ApplicationDbContext db, HttpContext ctx) =>
        {
            if (!ctx.User.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipments = await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => s.ToDto())
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // GET shipment by tracking number (customers)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            return shipment is null ? Results.NotFound() : Results.Ok(shipment.ToDto());
        });

        // GET shipments for current customer
        group.MapGet("/my", async (ApplicationDbContext db, HttpContext ctx) =>
        {
            var userId = ctx.User.FindFirst(System.Security.Claims.ClaimTypes.NameIdentifier)?.Value;
            if (userId is null) return Results.Unauthorized();

            var shipments = await db.Shipments
                .Where(s => s.CustomerId == userId)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => s.ToDto())
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // PUT update shipment status (dispatchers only)
        group.MapPut("/{id:int}/status", async (int id, UpdateStatusRequest req, ApplicationDbContext db, HttpContext ctx) =>
        {
            if (!ctx.User.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = req.Status;
            if (req.Notes is not null)
                shipment.Notes = req.Notes;

            await db.SaveChangesAsync();
            return Results.Ok(shipment.ToDto());
        });

        // POST create shipment (dispatchers only)
        group.MapPost("/", async (CreateShipmentRequest req, ApplicationDbContext db, HttpContext ctx) =>
        {
            if (!ctx.User.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipment = new Shipment
            {
                TrackingNumber = req.TrackingNumber,
                Origin = req.Origin,
                Destination = req.Destination,
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = req.EstimatedDelivery,
                RecipientName = req.RecipientName,
                CustomerId = req.CustomerId,
                Notes = req.Notes
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", shipment.ToDto());
        });
    }
}

public record UpdateStatusRequest(ShipmentStatus Status, string? Notes);

public record CreateShipmentRequest(
    string TrackingNumber,
    string Origin,
    string Destination,
    DateTime EstimatedDelivery,
    string RecipientName,
    string? CustomerId,
    string? Notes);

