arguments.file_text:
@page "/dispatch"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http

<PageTitle>Dispatch Dashboard</PageTitle>

<h1>Shipment Dispatch Dashboard</h1>

<div class="mb-3 d-flex gap-2">
    <input class="form-control" style="max-width: 300px;" placeholder="Filter by destination..."
           @bind="filterText" @bind:event="oninput" />
    <select class="form-select" style="max-width: 200px;" @bind="filterStatus">
        <option value="">All Statuses</option>
        @foreach (var status in Enum.GetValues<ShipmentStatus>())
        {
            <option value="@status">@status</option>
        }
    </select>
    <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showCreate)
{
    <div class="card mb-3 p-3">
        <h5>Create Shipment</h5>
        <div class="row g-2">
            <div class="col-md-3">
                <input class="form-control" placeholder="Tracking #" @bind="newShipment.TrackingNumber" />
            </div>
            <div class="col-md-3">
                <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
            </div>
            <div class="col-md-3">
                <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
            </div>
            <div class="col-md-3">
                <input class="form-control" placeholder="Recipient" @bind="newShipment.RecipientName" />
            </div>
            <div class="col-md-3">
